<?php

namespace Database\Seeders;

use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;

class BorPilotSeeder extends Seeder
{
    // Seeded all 238 pilots T-T
    public function run(): void
    {
        // I skip the insert if records already exist to avoid duplicates on re-seed
        if (DB::table('bor_pilots')->count() > 0) {
            return;
        }

        // I split the insert into chunks of 50 to avoid hitting memory or query size limits
        $pilots = $this->getPilots();
        $chunks = array_chunk($pilots, 50);

        foreach ($chunks as $chunk) {
            DB::table('bor_pilots')->insert($chunk);
        }
    }

